sql:
SELECT COUNT(data_element_id) 
FROM data_elements 
WHERE min > 0;

SELECT MAX(max) AS highest_max_value
FROM data_elements
WHERE min > 0;

SELECT data_element_id
FROM data_elements
WHERE data_standard_id = 1 AND is_required = 1;

SELECT label
FROM data_elements
WHERE data_element_id = 1;

SELECT name
FROM data_standards
WHERE data_standard_id = 1;

SELECT COUNT(data_format_id) 
FROM data_formats 
WHERE is_active = 1;

